content:
{
  "schemaVersion": 3,
  "judgeId": "judge_2",
  "batchIndex": 4,
  "comparisons": [
    {
      "leftId": "c5_shrimp_paste",
      "rightId": "dt_01_concept_06",
      "winnerId": "c5_shrimp_paste",
      "reason": "c5 có vòng lặp thưởng cực kỳ rõ ràng và phù hợp với nhịp đọc nhẹ nhàng: 10 ngày một mẻ mắm tép xổi, thu tiền lẻ ngay để xoay vòng vốn. Cơ chế thính gạo và kiểm soát nhiệt độ ủ mắm mang tính chuyên môn cao hơn việc cải tạo thuyền của concept 06."
    },
    {
      "leftId": "c5_shrimp_paste",
      "rightId": "dt_01_concept_07",
      "winnerId": "c5_shrimp_paste",
      "reason": "c5 tập trung vào kỹ thuật sinh hóa (lên men) và giải quyết mâu thuẫn thiếu gạo làm thính rất thực tế với bối cảnh 1980s. Concept 07 hơi nặng về tư duy marketing hiện đại, không tạo cảm giác 'làm giàu bằng tay nghề' mộc mạc như c5."
    },
    {
      "leftId": "c5_shrimp_paste",
      "rightId": "dt_01_concept_08",
      "winnerId": "c5_shrimp_paste",
      "reason": "c5 thể hiện agency của nhân vật chính qua việc chủ động chế biến phụ phẩm (moi nát) thành hàng hóa. Concept 08 dựa quá nhiều vào ký ức về vị trí bãi sò, vi phạm ranh giới về việc dùng tọa độ chính xác từ tương lai."
    },
    {
      "leftId": "c5_shrimp_paste",
      "rightId": "dt_01_concept_09",
      "winnerId": "c5_shrimp_paste",
      "reason": "c5 có cơ chế 3 chương đầu rất tốt, kích hoạt hành động ngay lập tức và có bữa cơm mắm chưng thịt ấm lòng. Concept 09 về muối có tiềm năng nhưng mâu thuẫn với thương lái ở giai đoạn đầu chưa đủ gắt để tạo động lực như c5."
    },
    {
      "leftId": "c5_shrimp_paste",
      "rightId": "dt_01_concept_10",
      "winnerId": "c5_shrimp_paste",
      "reason": "Concept 10 về du lịch văn hóa hoàn toàn không phù hợp với bối cảnh kinh tế Việt Nam năm 1988 và gu độc giả nam tần thích làm giàu thực dụng. c5 thắng tuyệt đối về độ khớp bối cảnh."
    },
    {
      "leftId": "c6_handline_bait",
      "rightId": "c7_live_seafood_transport",
      "winnerId": "c7_live_seafood_transport",
      "reason": "c7 có cơ chế cơ khí ứng dụng (bơm xe đạp, van một chiều) cực kỳ sáng tạo và đậm chất Việt Nam thời bao cấp. Việc vận chuyển bề bề sống quãng đường 20km bằng sức người tạo ra chi phí thật và nỗ lực cá nhân thuyết phục hơn c6."
    },
    {
      "leftId": "c6_handline_bait",
      "rightId": "c8_light_luring_squid",
      "winnerId": "c8_light_luring_squid",
      "reason": "c8 giải quyết bài toán vật tư (dầu hỏa khan hiếm) và kỹ thuật (chóa đèn nhôm) rất tốt. Cơ chế dụ mực bằng ánh sáng có tính biến hóa cao trong 30 chương (từ thúng đến đội tàu) hơn là câu tay đơn lẻ của c6."
    },
    {
      "leftId": "c6_handline_bait",
      "rightId": "c9_oyster_spat_poles",
      "winnerId": "c9_oyster_spat_poles",
      "reason": "c9 giới thiệu mô hình nuôi trồng thủy sản ven bờ, khớp với yêu cầu về sinh kế bền vững ở giai đoạn sau. Cơ chế 'lấy ngắn nuôi dài' (bắt cá đối quanh cọc hàu) rất thực tế và thông minh."
    },
    {
      "leftId": "c6_handline_bait",
      "rightId": "c10_net_modifications",
      "winnerId": "c10_net_modifications",
      "reason": "c10 tập trung vào tay nghề vá lưới và kiến thức thủy động lực học để giúp đỡ cả cộng đồng, tạo ra uy tín và quan hệ xã hội sâu sắc hơn là việc đi câu bí mật của c6."
    },
    {
      "leftId": "c6_handline_bait",
      "rightId": "dt_01_concept_01",
      "winnerId": "dt_01_concept_01",
      "reason": "Concept 01 khai thác đúng phần sản lượng bị đánh giá thấp (trứng cá, nội tạng) và biến nó thành bữa cơm gia đình ngay chương 2. c6 bắt được cá mú bán lấy tiền to ngay chương 3 hơi thiếu quá trình tích lũy tình cảm."
    },
    {
      "leftId": "c6_handline_bait",
      "rightId": "dt_01_concept_02",
      "winnerId": "dt_01_concept_02",
      "reason": "Concept 02 có mâu thuẫn nội tâm và xã hội (khoa học vi sinh vs kinh nghiệm dân gian) rất mạnh. Cơ chế cứu mẻ mắm hỏng ở chương 2 thể hiện năng lực nhân vật chính rõ nét hơn c6."
    },
    {
      "leftId": "c6_handline_bait",
      "rightId": "dt_01_concept_03",
      "winnerId": "dt_01_concept_03",
      "reason": "Concept 03 có nền tảng kỹ thuật cơ khí hải quân áp dụng vào việc sửa lưới rách do lỗi thiết kế, mang tính logic và agency cao. c6 dựa hơi nhiều vào may mắn tìm được rạn san hô chìm."
    },
    {
      "leftId": "c6_handline_bait",
      "rightId": "dt_01_concept_04",
      "winnerId": "dt_01_concept_04",
      "reason": "Concept 04 khai thác rong biển - một tài nguyên bị coi là rác, rất khớp với yêu cầu 'nhận ra giá trị bị đánh giá thấp'. Quá trình thử nghiệm món chè rong biển tạo cảm giác khoái hoạt và mới mẻ."
    },
    {
      "leftId": "c6_handline_bait",
      "rightId": "dt_01_concept_05",
      "winnerId": "dt_01_concept_05",
      "reason": "Concept 05 giải quyết điểm nghẽn lớn nhất của ngành cá thời đó là bảo quản lạnh. Cơ chế hầm đá bằng trấu và xơ dừa rất thực tế và có tính ứng dụng cao cho cả vùng biển."
    },
    {
      "leftId": "c6_handline_bait",
      "rightId": "dt_01_concept_06",
      "winnerId": "dt_01_concept_06",
      "reason": "Concept 06 có mâu thuẫn gia đình (cha bán thuyền) tạo động lực mạnh mẽ. Việc cải tạo mũi thuyền để tiết kiệm dầu là một cơ chế kỹ thuật cụ thể, khớp với yêu cầu làm giàu bằng tay nghề."
    },
    {
      "leftId": "c6_handline_bait",
      "rightId": "dt_01_concept_07",
      "winnerId": "dt_01_concept_07",
      "reason": "Concept 07 nâng tầm con moi (ruốc) bằng quy trình sấy sạch, tạo ra sản phẩm cao cấp. Điều này có tính hệ thống và khả năng mở rộng quy mô tốt hơn việc đi câu cá mú đơn lẻ."
    },
    {
      "leftId": "c6_handline_bait",
      "rightId": "dt_01_concept_08",
      "winnerId": "dt_01_concept_08",
      "reason": "Concept 08 giải quyết vấn đề sinh kế cho cả làng khi nguồn sò huyết cạn kiệt. Tính lãnh đạo cộng đồng và kiến thức sinh thái bền vững giúp nó vượt qua c6."
    },
    {
      "leftId": "c6_handline_bait",
      "rightId": "dt_01_concept_09",
      "winnerId": "dt_01_concept_09",
      "reason": "Concept 09 khai thác domain muối biển rất đặc trưng và ít trùng lặp. Việc phân loại muối để tối ưu hóa giá trị sử dụng là một cơ chế thông minh, đúng chất chuyên gia trọng sinh."
    },
    {
      "leftId": "c6_handline_bait",
      "rightId": "dt_01_concept_10",
      "winnerId": "c6_handline_bait",
      "reason": "c6 thắng vì concept 10 quá xa rời thực tế năm 1988. Việc thu tiền du lịch trải nghiệm ở một làng chài nghèo thời điểm đó là không khả thi và không tạo được cảm giác 'làm giàu' cho độc giả nam tần."
    },
    {
      "leftId": "c7_live_seafood_transport",
      "rightId": "c8_light_luring_squid",
      "winnerId": "c7_live_seafood_transport",
      "reason": "c7 thắng nhờ cơ chế 'vận chuyển giữ sống' tạo ra chênh lệch giá trị cực lớn (hàng sống vs hàng chết) và đòi hỏi nỗ lực thể chất (đạp xe) lẫn trí tuệ (chế máy sục khí từ phế liệu) rất cao, tạo cảm giác thành quả xứng đáng."
    }
  ]
}
